        $g = (float)($item['gst'] ?? 0);
        $a = $q * $r;
        $calcSubtotal += $a;
        $calcGst      += $a * $g / 100;
      }
      $discountAmt = (float)($inv['discount_amt'] ?? 0);
      $discountPct = (float)($inv['discount_pct'] ?? 0);
      if ($discountAmt == 0 && $discountPct > 0) {
        $discountAmt = $calcSubtotal * $discountPct / 100;
      }
      $calcGrandTotal = $calcSubtotal - $discountAmt + $calcGst;
    ?>
    <tfoot>
      <tr class="tfoot-row"><td colspan="7"><div class="tfoot-inner"><span class="lbl">Subtotal</span><span class="val"><?= fmt_inr($calcSubtotal, $sym) ?></span></div></td></tr>
