        $amtAfterDisc = $calcSubtotal - $discountAmt;
        $discFactor   = $calcSubtotal > 0 ? (1 - $discountAmt / $calcSubtotal) : 1;
        $calcGstAfter = $calcGst * $discFactor;
        $calcGrandTotal = $amtAfterDisc + $calcGstAfter;
      ?>
