      <?php endif; ?>
      <tr class="tfoot-grand"><td colspan="7"><div class="tfoot-inner"><span class="lbl">Grand Total</span><span class="val"><?= fmt_inr($calcGrandTotal, $sym) ?></span></div></td></tr>
