    </div>
    <?php endforeach; ?>
    <div class="line-tfoot">
      <div class="line-tfoot-row"><span>Subtotal</span><span style="font-family:var(--mono)"><?= fmt_inr($mc_subtotal, $sym) ?></span></div>
      <?php if ($mc_discount > 0):
