        $mc_disc_pct    = (float)($inv['discount_pct'] ?? 0);
      ?>
      <div class="line-tfoot-row" style="color:var(--red)">
        <span>Discount<?= $mc_disc_pct > 0 ? ' (' . (int)$mc_disc_pct . '%)' : '' ?></span>
